def populate_trippoints(apps, schema_editor):
    """
    Переносит плоские поля погрузки/выгрузки из Trip в TripPoint.
    Для каждого рейса создаёт две точки:
      sequence=1, type=LOAD  — из полей loading_*
      sequence=2, type=UNLOAD — из полей unloading_*
    Плоские поля Trip не трогаются (legacy до явного удаления).
    """
