    points_to_create = []

    for trip in Trip.objects.all():
        # Точка погрузки
        points_to_create.append(
            TripPoint(
                trip=trip,
                point_type="LOAD",
                sequence=1,
                address=trip.loading_address or "",
                planned_date=trip.planned_loading_date,
                actual_date=trip.actual_loading_date,
                contact_name=trip.loading_contact_name or "",
                contact_phone=trip.loading_contact_phone or "",
                loading_type=trip.loading_type or "",
            )
        )
        # Точка выгрузки
        points_to_create.append(
            TripPoint(
                trip=trip,
                point_type="UNLOAD",
                sequence=2,
                address=trip.unloading_address or "",
                planned_date=trip.planned_unloading_date,
                actual_date=trip.actual_unloading_date,
                contact_name=trip.unloading_contact_name or "",
                contact_phone=trip.unloading_contact_phone or "",
                loading_type=trip.unloading_type or "",
            )
        )

    TripPoint.objects.bulk_create(points_to_create)


